package config

import (
	couchbasev1 "github.com/couchbase/couchbase-operator/pkg/apis/couchbase/v1"

	appsv1 "k8s.io/api/apps/v1"
	corev1 "k8s.io/api/core/v1"
	rbacv1 "k8s.io/api/rbac/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/util/intstr"
)

const (
	// OperatorResourceName is the name used for all resources generated by the individual functions.
	OperatorResourceName = "couchbase-operator"
)

// DumpAdmissionYAML dumps all operator resources to standard out.
func DumpOperatorYAML(conf *Config) error {
	if conf.NoOperator {
		return nil
	}

	if err := DumpYAML(conf, "operator-service-account", GetOperatorServiceAccount()); err != nil {
		return err
	}
	if err := DumpYAML(conf, "operator-cluster-role", GetOperatorClusterRole()); err != nil {
		return err
	}
	if err := DumpYAML(conf, "operator-cluster-role-binding", GetOperatorClusterRoleBinding(conf.Namespace)); err != nil {
		return err
	}
	if err := DumpYAML(conf, "operator-deployment", GetOperatorDeployment(conf.OperatorImage, conf.ImagePullSecret)); err != nil {
		return err
	}
	return nil
}

// GetOperatorClusterRole generates the cluster role to run with.
func GetOperatorClusterRole() *rbacv1.ClusterRole {
	return &rbacv1.ClusterRole{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "rbac.authorization.k8s.io/v1",
			Kind:       "ClusterRole",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name: OperatorResourceName,
		},
		Rules: []rbacv1.PolicyRule{
			{
				APIGroups: []string{
					couchbasev1.GroupName,
				},
				Resources: []string{
					couchbasev1.CRDResourcePlural,
				},
				Verbs: []string{
					"*",
				},
			},
			{
				APIGroups: []string{
					"storage.k8s.io",
				},
				Resources: []string{
					"storageclasses",
				},
				Verbs: []string{
					"get",
				},
			},
			{
				APIGroups: []string{
					"apiextensions.k8s.io",
				},
				Resources: []string{
					"customresourcedefinitions",
				},
				Verbs: []string{
					"*",
				},
			},
			{
				APIGroups: []string{
					"",
				},
				Resources: []string{
					"pods",
					"pods/exec",
					"services",
					"endpoints",
					"persistentvolumeclaims",
					"persistentvolumes",
					"events",
					"secrets",
				},
				Verbs: []string{
					"*",
				},
			},
			{
				APIGroups: []string{
					"",
				},
				Resources: []string{
					"persistentvolumes",
				},
				Verbs: []string{
					"get",
					"watch",
				},
			},
			{
				APIGroups: []string{
					"apps",
				},
				Resources: []string{
					"deployments",
				},
				Verbs: []string{
					"*",
				},
			},
			{
				APIGroups: []string{
					"policy"},
				Resources: []string{
					"poddisruptionbudgets"},
				Verbs: []string{
					"*"},
			},
		},
	}
}

// GetOperatorServiceAccount generates the service account to run as.
func GetOperatorServiceAccount() *corev1.ServiceAccount {
	return &corev1.ServiceAccount{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "v1",
			Kind:       "ServiceAccount",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name: OperatorResourceName,
		},
	}
}

// GetOperatorClusterRoleBinding generates the cluster role binding linking the role to the service account.
func GetOperatorClusterRoleBinding(namespace string) *rbacv1.ClusterRoleBinding {
	return &rbacv1.ClusterRoleBinding{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "rbac.authorization.k8s.io/v1",
			Kind:       "ClusterRoleBinding",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name: OperatorResourceName,
		},
		Subjects: []rbacv1.Subject{
			{
				Kind:      "ServiceAccount",
				Name:      OperatorResourceName,
				Namespace: namespace,
			},
		},
		RoleRef: rbacv1.RoleRef{
			APIGroup: "rbac.authorization.k8s.io",
			Kind:     "ClusterRole",
			Name:     OperatorResourceName,
		},
	}
}

// GetOperatorDeployment returns the canonical way to run the operator.
func GetOperatorDeployment(image string, imagePullSecret string) *appsv1.Deployment {
	replicas := int32(1)
	deployment := &appsv1.Deployment{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "apps/v1",
			Kind:       "Deployment",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name: OperatorResourceName,
		},
		Spec: appsv1.DeploymentSpec{
			Replicas: &replicas,
			Selector: &metav1.LabelSelector{
				MatchLabels: map[string]string{
					"app": OperatorResourceName,
				},
			},
			Template: corev1.PodTemplateSpec{
				ObjectMeta: metav1.ObjectMeta{
					Labels: map[string]string{
						"app": OperatorResourceName,
					},
				},
				Spec: corev1.PodSpec{
					ServiceAccountName: OperatorResourceName,
					Containers: []corev1.Container{
						{
							Name:  OperatorResourceName,
							Image: image,
							Command: []string{
								OperatorResourceName,
							},
							Args: []string{
								"--pod-create-timeout=10m",
							},
							Env: []corev1.EnvVar{
								{
									Name: "MY_POD_NAMESPACE",
									ValueFrom: &corev1.EnvVarSource{
										FieldRef: &corev1.ObjectFieldSelector{
											FieldPath: "metadata.namespace",
										},
									},
								},
								{
									Name: "MY_POD_NAME",
									ValueFrom: &corev1.EnvVarSource{
										FieldRef: &corev1.ObjectFieldSelector{
											FieldPath: "metadata.name",
										},
									},
								},
							},
							Ports: []corev1.ContainerPort{
								{
									Name:          "http",
									ContainerPort: 8080,
								},
							},
							ReadinessProbe: &corev1.Probe{
								Handler: corev1.Handler{
									HTTPGet: &corev1.HTTPGetAction{
										Path: "/readyz",
										Port: intstr.FromString("http"),
									},
								},
								InitialDelaySeconds: 3,
								PeriodSeconds:       3,
								FailureThreshold:    20,
							},
						},
					},
				},
			},
		},
	}
	if imagePullSecret != "" {
		deployment.Spec.Template.Spec.ImagePullSecrets = []corev1.LocalObjectReference{
			{
				Name: imagePullSecret,
			},
		}
	}
	return deployment
}
